5	    <div class="auth-card card">
6	        <h2>Confirm Appointment</h2>
7	        <p><strong>Date:</strong> {{ slot.date }}</p>
8	        <p><strong>Time:</strong> {{ slot.start_time.strftime('%H:%M') }} — {{ slot.end_time.strftime('%H:%M') }}</p>
9	        <p><strong>Clinician:</strong> {{ slot.clinician.user.username }}</p>
10	
11	        {% if remaining_seconds > 0 %}
12	        <div class="alert alert-warning" id="hold-timer">
13	            Hold expires in <span id="countdown">{{ remaining_seconds }}</span> seconds
14	        </div>
15	        <script>
16	        (function(){
17	            var r={{ remaining_seconds }};
18	            var el=document.getElementById('countdown');
19	            setInterval(function(){
20	                r--;
21	                if(r<=0){el.textContent='0';document.getElementById('hold-timer').innerHTML='Hold expired. Please try again.';}
22	                else{var m=Math.floor(r/60),s=r%60;el.textContent=(m>0?m+'m ':'')+s+'s';}
23	            },1000);
24	        })();
25	        </script>
26	        {% endif %}
27	
28	        <form method="POST" style="margin-top:1rem;">
29	            <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
30	            <button type="submit" class="btn btn-primary btn-block">Confirm Booking</button>
