1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>{% block title %}MeridianCare{% endblock %}</title>
7	    <link rel="stylesheet" href="{{ url_for('static', filename='css/style.css') }}">
8	    <meta name="csrf-token" content="{{ csrf_token() }}">
9	    <script src="{{ url_for('static', filename='js/htmx.min.js') }}"></script>
10	    {% block extra_head %}{% endblock %}
11	</head>
12	<body hx-headers='{"X-CSRFToken": "{{ csrf_token() }}"}'>
13	    <div id="htmx-indicator" class="htmx-indicator">
14	        <div class="spinner"></div>
15	    </div>
16	
17	    <header class="site-header">
18	        <div class="container header-content">
19	            <a href="/" class="logo" hx-get="/" hx-target="#main-content" hx-push-url="true">
20	                <span class="logo-icon">&#9764;</span>
21	                MeridianCare
22	            </a>
23	            <nav class="main-nav" id="main-nav">
24	                {% block nav %}
25	                {% if current_user.is_authenticated %}
26	                    <a href="/" hx-get="/" hx-target="#main-content" hx-push-url="true">Home</a>
27	                    {% if current_user.role == 'patient' %}
28	                    <a href="{{ url_for('patient.demographics') }}" hx-get="{{ url_for('patient.demographics') }}" hx-target="#main-content" hx-push-url="true">My Profile</a>
29	                    {% endif %}
30	                    {% if current_user.role in ('administrator', 'clinician', 'front_desk') %}
31	                    <a href="{{ url_for('staff.patient_list') }}" hx-get="{{ url_for('staff.patient_list') }}" hx-target="#main-content" hx-push-url="true">Patients</a>
32	                    <a href="{{ url_for('visits.dashboard') }}" hx-get="{{ url_for('visits.dashboard') }}" hx-target="#main-content" hx-push-url="true">Visits</a>
33	                    {% endif %}
34	                    {% if current_user.role == 'patient' %}
35	                    <a href="{{ url_for('reminders.my_reminders') }}" hx-get="{{ url_for('reminders.my_reminders') }}" hx-target="#main-content" hx-push-url="true">
36	                        Reminders <span id="reminder-badge" hx-get="{{ url_for('reminders.reminder_count') }}" hx-trigger="load, every 60s" hx-swap="innerHTML"></span>
37	                    </a>
38	                    {% endif %}
39	                    {% if current_user.role == 'administrator' %}
40	                    <a href="{{ url_for('admin.users') }}" hx-get="{{ url_for('admin.users') }}" hx-target="#main-content" hx-push-url="true">Users</a>
41	                    <a href="{{ url_for('coverage.zones') }}" hx-get="{{ url_for('coverage.zones') }}" hx-target="#main-content" hx-push-url="true">Zones</a>
42	                    <a href="{{ url_for('audit.audit_log') }}" hx-get="{{ url_for('audit.audit_log') }}" hx-target="#main-content" hx-push-url="true">Audit</a>
43	                    <a href="{{ url_for('observability.observability') }}" hx-get="{{ url_for('observability.observability') }}" hx-target="#main-content" hx-push-url="true">System</a>
44	                    {% endif %}
45	                    <span style="color: var(--text-light); font-size: 0.9rem;">{{ current_user.username }} <span class="badge badge-primary">{{ current_user.role | replace('_', ' ') | title }}</span></span>
46	                    <form method="POST" action="{{ url_for('auth.logout') }}" style="display:inline;">
47	                        <input type="hidden" name="csrf_token" value="{{ csrf_token() }}">
48	                        <button type="submit" class="btn btn-secondary" style="padding:0.35rem 0.75rem;">Logout</button>
49	                    </form>
50	                {% else %}
51	                    <a href="{{ url_for('auth.login') }}" hx-get="{{ url_for('auth.login') }}" hx-target="#main-content" hx-push-url="true">Login</a>
52	                    <a href="{{ url_for('auth.register') }}" hx-get="{{ url_for('auth.register') }}" hx-target="#main-content" hx-push-url="true">Register</a>
53	                {% endif %}
54	                {% endblock %}
55	            </nav>
56	        </div>
57	    </header>
58	
59	    <main class="container" id="main-content" hx-indicator="#htmx-indicator">
60	        {% with messages = get_flashed_messages(with_categories=true) %}
61	            {% if messages %}
62	                {% for category, message in messages %}
63	                    <div class="alert alert-{{ category }}">{{ message }}</div>
64	                {% endfor %}
65	            {% endif %}
66	        {% endwith %}
67	        {% block content %}{% endblock %}
68	    </main>
69	
70	    <footer class="site-footer">
71	        <div class="container">
72	            <p>&copy; 2026 MeridianCare Clinic Operations Platform</p>
73	        </div>
74	    </footer>
75	
76	    {% block extra_scripts %}{% endblock %}
77	    <script>
78	    /* Inject a fresh nonce + timestamp into every HTMX POST so anti-replay
79	       is satisfied without needing per-form hidden fields for HTMX requests. */
80	    document.body.addEventListener('htmx:configRequest', function(evt) {
81	        if (evt.detail.verb === 'post') {
82	            evt.detail.parameters['_nonce'] = crypto.randomUUID();
83	            evt.detail.parameters['_timestamp'] = new Date().toISOString();
84	        }
85	    });
86	    </script>
87	</body>
88	</html>
